spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.33 && progress < 0.66) stage = 2;
    else if (progress >= 0.66) stage = 3;

    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Stage 1: 0.35 -> 35%
    if (stage === 1) {
      var localT = progress / 0.33; // 0 to 1

      ctx.font = 'bold 24px monospace';
      ctx.fillStyle = '#F3F4F6';

      // Draw characters at absolute spaces
      // '0'  '.'  '3'  '5'
      // If localT > 0.5, we show '%' and hide '0.'
      var xCenter = W / 2;
      var yCenter = H / 2 - 20;

      if (localT < 0.5) {
        ctx.fillText('0.35', xCenter, yCenter);

        // Draw hop arrows under the decimal
        ctx.strokeStyle = '#60A5FA';
        ctx.lineWidth = 2;
        // First hop
        ctx.beginPath();
        ctx.arc(xCenter - 14, yCenter + 15, 8, Math.PI, 0, true);
        ctx.stroke();
        // Second hop
        ctx.beginPath();
        ctx.arc(xCenter, yCenter + 15, 8, Math.PI, 0, true);
        ctx.stroke();

        ctx.fillStyle = '#60A5FA';
        ctx.font = 'bold 12px -apple-system, sans-serif';
        ctx.fillText('Move Right →', xCenter, yCenter + 35);
      } else {
        ctx.fillStyle = '#34D399';
        ctx.fillText('35%', xCenter, yCenter);

        ctx.fillStyle = '#10B981';
        ctx.font = 'bold 12px -apple-system, sans-serif';
        ctx.fillText('35% (Converted)', xCenter, yCenter + 35);
      }

      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Decimal to Percentage', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Shift the decimal point 2 places to the right.', W / 2, H - 22);
    }

    // Stage 2: 8% -> 0.08
    else if (stage === 2) {
      var localT = (progress - 0.33) / 0.33; // 0 to 1
      var xCenter = W / 2;
      var yCenter = H / 2 - 20;
      ctx.font = 'bold 24px monospace';

      if (localT < 0.5) {
        ctx.fillStyle = '#F3F4F6';
        ctx.fillText('8%', xCenter, yCenter);

        // Draw hop arrows going left
        ctx.strokeStyle = '#F59E0B';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(xCenter - 10, yCenter + 15, 8, 0, Math.PI, true);
        ctx.stroke();
        ctx.beginPath();
        ctx.arc(xCenter - 26, yCenter + 15, 8, 0, Math.PI, true);
        ctx.stroke();

        ctx.fillStyle = '#F59E0B';
        ctx.font = 'bold 12px -apple-system, sans-serif';
        ctx.fillText('← Move Left', xCenter, yCenter + 35);
      } else {
        ctx.fillStyle = '#F59E0B';
        ctx.fillText('0.08', xCenter, yCenter);

        ctx.font = 'bold 12px -apple-system, sans-serif';
        ctx.fillText('0.08 (Added zero placeholder)', xCenter, yCenter + 35);
      }

      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Percentage to Decimal', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Shift left 2 places. Put a placeholder 0 in front of 8.', W / 2, H - 22);
    }

    // Stage 3: 1.4 -> 140%
    else {
      var localT = (progress - 0.66) / 0.34; // 0 to 1
      var xCenter = W / 2;
      var yCenter = H / 2 - 20;
      ctx.font = 'bold 24px monospace';

      if (localT < 0.5) {
        ctx.fillStyle = '#F3F4F6';
        ctx.fillText('1.4', xCenter, yCenter);

        ctx.strokeStyle = '#8B5CF6';
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc(xCenter - 4, yCenter + 15, 8, Math.PI, 0, true);
        ctx.stroke();
        ctx.beginPath();
        ctx.arc(xCenter + 12, yCenter + 15, 8, Math.PI, 0, true);
        ctx.stroke();

        ctx.fillStyle = '#8B5CF6';
        ctx.font = 'bold 12px -apple-system, sans-serif';
        ctx.fillText('Need a second place!', xCenter, yCenter + 35);
      } else {
        ctx.fillStyle = '#A78BFA';
        ctx.fillText('140%', xCenter, yCenter);

        ctx.font = 'bold 12px -apple-system, sans-serif';
        ctx.fillText('Add a zero: 1.40 becomes 140%', xCenter, yCenter + 35);
      }

      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Padding Trailing Zeros', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Add trailing zeros to decimal places if you run out of digits.', W / 2, H - 22);
    }
  }
};
